INSERT INTO `hub_feedbacks` VALUES ('1b0e1d9a-36ad-4889-a903-379053353b62','cmnsk4np80000o8ef5qlej1mr','COMPLETED','\"\\n\\n⚖️ Điểm tựa pháp luật\\n\\nLĩnh vực: Thuế\\n\\nĐiều khoản: Điều 8, Khoản 1, Luật Thuế thu nhập cá nhân 2007\\n\\n🔍 Nhận định tình huống\\n\\nHợp pháp. Bạn có thu nhập chịu thuế từ tiền lương, tiền công.\\n\\n🛠️ Lộ trình xử lý\\n\\nBước 1: Đăng ký tờ khai thuế thu nhập cá nhân tại cơ quan thuế.\\n\\nBước 2: Nộp tờ khai và bảng lương cho cơ quan thuế.\\n\\nBước 3: Đóng thuế theo mức độ chịu thuế.\\n\\n⚠️ Cảnh báo đỏ\\n\\nRủi ro: Phạt tiền nếu không nộp tờ khai thuế đúng hạn.\\n\\nLưu ý: Đăng ký tờ khai thuế ngay khi có thu nhập.\"','2026-04-10 07:05:06.600','2026-04-10 07:05:06.600');
/*!40000 ALTER TABLE `hub_feedbacks` ENABLE KEYS */;
UNLOCK TABLES;

