INSERT INTO `schedule_blog_system` VALUES ('1',1,'meta/llama-3.1-8b','Bạn là một luật sư dày dặn kinh nghiệm và là một chuyên gia content marketing. Hãy lập danh sách các tiêu đề bài viết blog cho lĩnh vực luật. Yêu cầu: \n- Tập trung vào những sai lầm phổ biến mà người dân thường mắc phải. ý tưởng phải mang tính thời sự/tranh luận.\n- Dựa vào tags đã có sẵn mà tạo ý tưởng  liên quan','2026-04-10 08:38:24.158');
